45	void paillier_gen_interactive_t::step3_p1_to_p2(const crypto::paillier_t& paillier, const bn_t& x1,
46	                                                const ecc_point_t& Q1, const crypto::mpc_pid_t& prover_pid, mem_t sid) {
47	  valid.prove(paillier, valid_m1, prover_pid, valid_m2);
48	  equal.prover_msg2(paillier, x1, r_key, rho);
49	  range.prover_msg2(x1, rho);
50	  pdl.paillier_range_exp_slack_proof = zk::zk_flag::skip;
51	  pdl.prove(c_key, paillier, Q1, x1, r_key, sid, 0);
52	}
