85	error_t dkg(job_2p_t& job, ecurve_t curve, key_t& key) {
86	  error_t rv = UNINITIALIZED_ERROR;
87	
88	  key.curve = curve;
89	  const mod_t& q = curve.order();
90	
91	  paillier_gen_interactive_t paillier_gen(job.get_pid(party_t::p1));
92	  eckey::dkg_2p_t ec_dkg(curve, job.get_pid(party_t::p1));
93	
94	  key.x_share = bn_t::rand(q);
95	  key.role = job.get_party();
96	
97	  if (job.is_p1()) {
98	    ec_dkg.step1_p1_to_p2(key.x_share);
99	    paillier_gen.step1_p1_to_p2(key.paillier, key.x_share, ec_dkg.curve.order(), key.c_key);
100	  }
101	
102	  if (rv = job.p1_to_p2(ec_dkg.msg1, paillier_gen.msg1, key.c_key)) return rv;
103	  if (paillier_gen.c_key != key.c_key) return coinbase::error(E_CRYPTO, "paillier_gen.c_key != key.c_key");
104	
105	  if (job.is_p2()) {
106	    ec_dkg.step2_p2_to_p1(key.x_share);
107	    paillier_gen.step2_p2_to_p1();
108	  }
109	
110	  if (rv = job.p2_to_p1(ec_dkg.msg2, paillier_gen.msg2)) return rv;
111	
112	  if (job.is_p1()) {
113	    if (rv = ec_dkg.step3_p1_to_p2(key.Q)) return rv;
114	    paillier_gen.step3_p1_to_p2(key.paillier, key.x_share, ec_dkg.Q1, job.get_pid(party_t::p1), ec_dkg.sid);
115	  }
116	
117	  if (rv = job.p1_to_p2(ec_dkg.msg3, paillier_gen.msg3)) return rv;
118	
119	  if (job.is_p2()) {
120	    if (rv = ec_dkg.step4_output_p2(key.Q)) return rv;
121	    if (rv = paillier_gen.step4_p2_output(key.paillier, ec_dkg.Q1, paillier_gen.c_key, job.get_pid(party_t::p1),
122	                                          ec_dkg.sid))
123	      return rv;
124	  }
125	  return SUCCESS;
126	}
