128	error_t refresh(job_2p_t& job, const key_t& key, key_t& new_key) {
129	  error_t rv = UNINITIALIZED_ERROR;
130	  cb_assert(job.is_party(key.role));
131	  new_key.role = key.role;
132	  new_key.curve = key.curve;
133	  new_key.Q = key.Q;
134	
135	  const mod_t& q = key.curve.order();
136	
137	  bn_t N_tag;
138	  bn_t rho1, rho2;
139	  coinbase::crypto::commitment_t com(job.get_pid(party_t::p1));
140	  bn_t r_key, r_key_tag, c_key_tag;
141	  zk::two_paillier_equal_interactive_t zk_two_paillier_equal(job.get_pid(party_t::p1));
142	  zk::two_paillier_equal_interactive_t::prover_msg1_t pi1_P;
143	
144	  if (job.is_p1()) {
145	    rho1 = bn_t::rand(q);
146	    com.gen(rho1);
147	
148	    new_key.paillier.generate();
149	    N_tag = new_key.paillier.get_N();
150	    r_key_tag = bn_t::rand(N_tag);
151	    c_key_tag = new_key.paillier.encrypt(key.x_share, r_key_tag);
152	    r_key = key.paillier.get_cipher_randomness(key.x_share, key.c_key);
153	    zk_two_paillier_equal.prover_msg1(q, key.paillier, new_key.paillier, pi1_P);
154	  }
155	
156	  if (rv = job.p1_to_p2(com.msg, N_tag, c_key_tag, pi1_P)) return rv;
157	
158	  zk::two_paillier_equal_interactive_t::verifier_challenge_msg_t pi2_V;
159	  zk::valid_paillier_interactive_t zk_valid_paillier_interactive;
160	  zk::valid_paillier_interactive_t::challenge_msg_t pi1_V_tag;
161	  if (job.is_p2()) {
162	    if (N_tag <= 0) return rv = job.mpc_abort(E_CRYPTO, "N' < 0");
163	    const int N_tag_bits = N_tag.get_bits_count();
164	    if (N_tag_bits < 3 * q.get_bits_count() + 3 * SEC_P_STAT + SEC_P_COM + 1)
165	      return coinbase::error(E_CRYPTO, "length of N < 3lg q+ 3 stat-sec-param + com-sec-param + 1");
166	    if (N_tag_bits < crypto::paillier_t::bit_size) return rv = job.mpc_abort(E_CRYPTO, "N' < 2048");
167	    if (N_tag_bits > crypto::paillier_t::bit_size)
168	      return rv = job.mpc_abort(E_CRYPTO, "unsupported Paillier modulus size");
169	
170	    if (rv = new_key.paillier.create_pub(N_tag)) return rv = job.mpc_abort(E_CRYPTO, "invalid Paillier modulus");
171	    // This includes the GCD check.
172	    if (rv = new_key.paillier.verify_cipher(c_key_tag)) return rv;
173	    rho2 = bn_t::rand(q);
174	
175	    zk_two_paillier_equal.verifier_challenge_msg(pi2_V);
176	    zk_valid_paillier_interactive.challenge(pi1_V_tag);
177	  }
178	
179	  if (rv = job.p2_to_p1(rho2, pi1_V_tag, pi2_V)) return rv;
180	
181	  zk::two_paillier_equal_interactive_t::prover_msg2_t pi3_P;
182	  zk::valid_paillier_interactive_t::prover_msg_t pi2_P_tag;
183	  if (job.is_p1()) {
184	    if (rv = zk_two_paillier_equal.prover_msg2(key.paillier, new_key.paillier, key.x_share, r_key, r_key_tag, pi2_V,
185	                                               pi3_P))
186	      return rv;
187	    zk_valid_paillier_interactive.prove(new_key.paillier, pi1_V_tag, job.get_pid(party_t::p1), pi2_P_tag);
188	  }
189	
190	  if (rv = job.p1_to_p2(rho1, com.rand, pi3_P, pi2_P_tag)) return rv;
191	
192	  if (job.is_p2()) {
193	    if (rv = zk_valid_paillier_interactive.verify(new_key.paillier, job.get_pid(party_t::p1), pi2_P_tag)) return rv;
194	
195	    // old key (key.c_key)
196	    zk_two_paillier_equal.p0_valid_key = zk::zk_flag::verified;
197	    zk_two_paillier_equal.p0_no_small_factors = zk::zk_flag::verified;
198	    zk_two_paillier_equal.c0_plaintext_range = zk::zk_flag::verified;
199	
200	    // new ciphertext (c_key_tag) will be checked inside the verify function
201	    zk_two_paillier_equal.p1_valid_key = zk::zk_flag::verified;
202	    zk_two_paillier_equal.p1_no_small_factors = zk::zk_flag::verified;
203	
204	    if (rv = zk_two_paillier_equal.verify(q, key.paillier, key.c_key, new_key.paillier, c_key_tag, pi1_P, pi3_P))
205	      return rv;
206	    if (rv = com.open(rho1)) return rv;
207	  }
208	
209	  bn_t rho;
210	  MODULO(q) { rho = rho1 + rho2; }
211	  new_key.c_key = new_key.paillier.add_scalar(c_key_tag, rho, crypto::paillier_t::rerand_e::off);
212	
213	  if (job.is_p1()) {
214	    // Side-channel / correctness note:
215	    // This update must be done as a *plain integer* addition (not reduced mod q), because we
216	    // also homomorphically apply the same shift to the Paillier-encrypted share:
217	    //   new_key.c_key = Enc_{N'}(key.x_share) ⊕ rho
218	    // so `new_key.x_share` is intended to match the Paillier plaintext representative (mod N'),
219	    // not the reduced scalar in Z_q.
220	    //
221	    // From a side-channel perspective, this `bn_t` addition currently goes through OpenSSL `BN_add`
222	    // and is not guaranteed constant-time. However, OpenSSL represents `BIGNUM`s as an array of
223	    // machine-word "limbs" (`BN_ULONG`, typically 64-bit), and `BN_add` is essentially a single
224	    // pass over those limbs with carry propagation. Here `rho < q`, but `key.x_share` is an integer
225	    // representative that may grow beyond q after refreshes. As a result, the only realistic
226	    // leakage from this single add is very coarse: the effective limb length ("top") / bitlength
227	    // and possibly a final carry-out. In practice that mostly correlates with how many times
228	    // refresh has been applied (i.e., the magnitude of the representative), not the underlying
229	    // secret scalar mod q. We accept this tradeoff because utilizing such small variation would
230	    // also require very accurate timing and many repeated measurements (typically only feasible
231	    // for a local/co-resident attacker); over the network this signal is dominated by noise.
232	    // Therefore, in our threat model this is not considered a real issue.
233	    new_key.x_share = key.x_share + rho;
234	  } else {
235	    MODULO(q) new_key.x_share = key.x_share - rho;
236	  }
237	
238	  return SUCCESS;
239	}
