241	error_t sign_batch_impl(job_2p_t& job, buf_t& sid, const key_t& key, const std::vector<mem_t>& msgs, int sign_mode_flag,
242	                        std::vector<buf_t>& sigs) {
243	  error_t rv = UNINITIALIZED_ERROR;
244	
245	  bool global_abort_mode = sign_mode_flag == SIGN_MODE_GLOBAL_ABORT;
246	
247	  auto n_sigs = msgs.size();
248	  if (n_sigs == 0) return coinbase::error(E_BADARG, "ecdsa_2p: empty batch");
249	  sigs.resize(n_sigs);
250	  const ecurve_t curve = key.curve;
251	  const auto& G = curve.generator();
252	  const mod_t& q = curve.order();
253	
254	  std::vector<bn_t> m(n_sigs);
255	  for (int i = 0; i < n_sigs; i++) {
256	    m[i] = curve_msg_to_bn(msgs[i], curve);
257	  }
258	
259	  if (sid.empty())
260	    if (rv = generate_sid_fixed_2p(job, party_t::p2, sid)) return rv;
261	
262	  std::vector<bn_t> k1;
263	  std::vector<bn_t> k2;
264	  zk::uc_batch_dl_t pi_1, pi_2;
265	  std::vector<ecc_point_t> R1;
266	  std::vector<ecc_point_t> R2(n_sigs);
267	  coinbase::crypto::commitment_t com(sid, job.get_pid(party_t::p1));
268	
269	  if (job.is_p1()) {
270	    k1.resize(n_sigs);
271	    R1.resize(n_sigs);
272	    for (int i = 0; i < n_sigs; i++) {
273	      k1[i] = curve.get_random_value();
274	      R1[i] = k1[i] * G;
275	    }
276	    pi_1.prove(R1, k1, sid, 1);
277	    // Adding msgs here serves as a way of checking the consistency of the input messages.
278	    com.gen(msgs, R1, pi_1);
279	  }
280	
281	  if (rv = job.p1_to_p2(com.msg)) return rv;
282	
283	  if (job.is_p2()) {
284	    k2.resize(n_sigs);
285	    for (int i = 0; i < n_sigs; i++) {
286	      k2[i] = curve.get_random_value();
287	      R2[i] = k2[i] * G;
288	    }
289	    pi_2.prove(R2, k2, sid, 2);
290	  }
291	
292	  if (rv = job.p2_to_p1(R2, pi_2)) return rv;
293	  if (job.is_p1() && R2.size() != n_sigs) return coinbase::error(E_CRYPTO, "ecdsa_2p: inconsistent batch size (R2)");
294	
295	  std::vector<ecc_point_t> R(n_sigs);
296	
297	  if (job.is_p1()) {
298	    // Checking that R2 values are valid is done in the verify function.
299	    if (rv = pi_2.verify(R2, sid, 2)) return rv;
300	    for (int i = 0; i < n_sigs; i++) {
301	      R[i] = k1[i] * R2[i];
302	    }
303	  }
304	
305	  if (rv = job.p1_to_p2(com.rand, R1, pi_1)) return rv;
306	
307	  std::vector<bn_t> c(n_sigs);
308	  std::vector<bn_t> r(n_sigs);
309	  std::vector<zk_ecdsa_sign_2pc_integer_commit_t> zk_ecdsa(n_sigs);
310	
311	  // This is the step 4, taken from the section in the spec called ZK Proof of Correctness for Message 4 from P2 to P1
312	  if (job.is_p2()) {
313	    if (R1.size() != n_sigs) return coinbase::error(E_CRYPTO, "ecdsa_2p: inconsistent batch size (R1)");
314	    if (rv = com.open(msgs, R1, pi_1)) return rv;
315	
316	    // Checking that R1 values are valid is done in the verify function.
317	    if (rv = pi_1.verify(R1, sid, 1)) return rv;
318	    for (int i = 0; i < n_sigs; i++) {
319	      R[i] = k2[i] * R1[i];
320	      r[i] = R[i].get_x() % q;
321	      bn_t rho = bn_t::rand((q * q) << (SEC_P_STAT * 2));
322	      bn_t rc;
323	      if (rv = key.paillier.rand_N_star(rc, /*resample_until_coprime=*/false))
324	        return coinbase::error(rv, "gcd(rc, N) != 1");
325	
326	      bn_t k2_inv;
327	      bn_t temp;
328	      MODULO(q) {
329	        k2_inv = k2[i].inv();
330	        temp = k2_inv * key.x_share;
331	      }
332	      temp = k2_inv * m[i] + temp * r[i] + rho * q;
333	      auto c_tag = key.paillier.enc(temp, rc);
334	
335	      // We turn off rerand for the paillier encryption and do not rerand the ciphertext at the end of the scope since
336	      // c_tag was generated with the fresh randomness rc.
337	      crypto::paillier_t::rerand_scope_t paillier_rerand(crypto::paillier_t::rerand_e::off);
338	      crypto::paillier_t::elem_t c_key_tag = key.paillier.elem(key.c_key) + (q << SEC_P_STAT);
339	      crypto::paillier_t::elem_t pai_c = (c_key_tag * (k2_inv * r[i])) + c_tag;
340	
341	      c[i] = pai_c.to_bn();
342	
343	      if (!global_abort_mode) {
344	        if (rv = zk_ecdsa[i].prove(key.paillier, c_key_tag, pai_c, key.x_share * G, R2[i], m[i], r[i], k2[i],
345	                                   key.x_share, rho, rc, sid, i))
346	          return rv;
347	      }
348	    }
349	  }
350	
351	  if (!global_abort_mode) {
352	    if (rv = job.p2_to_p1(c, zk_ecdsa)) return rv;
353	  } else {
354	    if (rv = job.p2_to_p1(c)) return rv;
355	  }
356	
357	  if (job.is_p1()) {
358	    if (c.size() != n_sigs) return coinbase::error(E_CRYPTO, "ecdsa_2p: inconsistent batch size (c)");
359	    if (!global_abort_mode && zk_ecdsa.size() != n_sigs)
360	      return coinbase::error(E_CRYPTO, "ecdsa_2p: inconsistent batch size (zk_ecdsa)");
361	    for (int i = 0; i < n_sigs; i++) {
362	      r[i] = R[i].get_x() % q;
363	
364	      if (!global_abort_mode) {
365	        crypto::paillier_t::rerand_scope_t paillier_rerand(crypto::paillier_t::rerand_e::off);
366	        crypto::paillier_t::elem_t c_key_tag = key.paillier.elem(key.c_key) + (q << SEC_P_STAT);
367	        crypto::paillier_t::elem_t pai_c = key.paillier.elem(c[i]);
368	
369	        ecc_point_t Q_pub_share = key.x_share * G;
370	        ecc_point_t Q_minus_xG;
371	        Q_minus_xG = key.Q - Q_pub_share;
372	        if (rv = zk_ecdsa[i].verify(curve, key.paillier, c_key_tag, pai_c, Q_minus_xG, R2[i], m[i], r[i], sid, i))
373	          return coinbase::error(rv, "zk_ecdsa_sign_2pc_integer_commit_t::verify failed");
374	      }
375	
376	      {
377	        crypto::vartime_scope_t vartime_scope;
378	        if (rv = key.paillier.verify_cipher(c[i]))
379	          return coinbase::error(rv, "ecdsa_2p: invalid Paillier ciphertext from counterparty");
380	      }
381	
382	      bn_t s = key.paillier.decrypt(c[i]);
383	      s = q.mod(s);
384	
385	      MODULO(q) { s /= k1[i]; }
386	
387	      bn_t q_minus_s = q - s;
388	      if (q_minus_s < s) s = q_minus_s;
389	
390	      crypto::ecdsa_signature_t sig(curve, r[i], s);
391	      sigs[i] = sig.to_der();
392	
393	      // verify
394	      crypto::ecc_pub_key_t ecc_verification_key(key.Q);
395	      if (rv = ecc_verification_key.verify(msgs[i], sigs[i]))
396	        if (global_abort_mode)
397	          return coinbase::error(E_ECDSA_2P_BIT_LEAK, "signature verification failed");
398	        else
399	          return coinbase::error(rv, "signature verification failed");
400	    }
401	  }
402	
403	  return SUCCESS;
404	}
