406	error_t sign_batch(job_2p_t& job, buf_t& sid, const key_t& key, const std::vector<mem_t>& msgs,
407	                   std::vector<buf_t>& sigs) {
408	  return sign_batch_impl(job, sid, key, msgs, SIGN_MODE_DEFAULT, sigs);
409	}
