433	
434	error_t zk_ecdsa_sign_2pc_integer_commit_t::prove(const crypto::paillier_t& paillier,
435	                                                  const crypto::paillier_t::elem_t& c_key,
436	                                                  const crypto::paillier_t::elem_t& c, const ecc_point_t& Q2,
437	                                                  const ecc_point_t& R2, const bn_t& m_tag, const bn_t& r,
438	                                                  const bn_t& k2, const bn_t& x2, const bn_t& rho, const bn_t& rc,
439	                                                  mem_t sid, uint64_t aux) {
440	  crypto::paillier_t::rerand_scope_t paillier_rerand(crypto::paillier_t::rerand_e::off);
441	
442	  const mod_t& N = paillier.get_N();
443	  ecurve_t curve = Q2.get_curve();
444	  const mod_t& q = curve.order();
445	
446	  const crypto::unknown_order_pedersen_params_t& params = crypto::unknown_order_pedersen_params_t::get();
447	  const mod_t& N_ped = params.N;
448	  const bn_t& g = params.g;
449	  const bn_t& h = params.h;
450	
451	  // This has nothing to do with the c_key_tag in the signing.
452	  // The c_key input here is actually c_key + q << SEC_P_STAT as required in the spec
453	  crypto::paillier_t::elem_t c_key_tag = r * c_key;
454	  bn_t w1;
455	  bn_t w2;
456	  MODULO(q) {
457	    w1 = k2.inv();
458	    w2 = w1 * x2;
459	  }
460	  bn_t w3 = rho;
461	  bn_t w4 = rc;
462	
463	  bn_t r1_w = bn_t::rand(N_ped << SEC_P_STAT);
464	  bn_t r2_w = bn_t::rand(N_ped << SEC_P_STAT);
465	  bn_t r3_w = bn_t::rand(N_ped << SEC_P_STAT);
466	
467	  MODULO(N_ped) {
468	    // Integer commitments
469	    W1 = g.pow(w1) * h.pow(r1_w);
470	    W2 = g.pow(w2) * h.pow(r2_w);
471	    W3 = g.pow(w3) * h.pow(r3_w);
472	  }
473	
474	  bn_t w1_tag = bn_t::rand(q << (SEC_P_STAT + SEC_P_COM));
475	  bn_t w2_tag = bn_t::rand(q << (SEC_P_STAT + SEC_P_COM));
476	  bn_t w3_tag = bn_t::rand((q * q) << (3 * SEC_P_STAT + SEC_P_COM));
477	
478	  bn_t r1_w_tag = bn_t::rand(N_ped << (2 * SEC_P_STAT + SEC_P_COM));
479	  bn_t r2_w_tag = bn_t::rand(N_ped << (2 * SEC_P_STAT + SEC_P_COM));
480	  bn_t r3_w_tag = bn_t::rand(N_ped << (2 * SEC_P_STAT + SEC_P_COM));
481	
482	  MODULO(N_ped) {
483	    // Integer commitments
484	    W1_tag = g.pow(w1_tag) * h.pow(r1_w_tag);
485	    W2_tag = g.pow(w2_tag) * h.pow(r2_w_tag);
486	    W3_tag = g.pow(w3_tag) * h.pow(r3_w_tag);
487	  }
488	
489	  G_tag = w1_tag * R2;
490	  Q2_tag = w2_tag * R2;
491	
492	  bn_t r_enc;
493	  if (error_t rv = paillier.rand_N_star(r_enc, /*resample_until_coprime=*/false))
494	    return coinbase::error(rv, "paillier_t::rand_N_star: gcd(r_enc, N) != 1");
495	
496	  bn_t temp = w1_tag * m_tag + w2_tag * r + w3_tag * q;
497	  crypto::paillier_t::elem_t C_enc_tag = paillier.enc(temp, r_enc) + (w1_tag * c_key_tag);
498	  this->C_enc_tag = C_enc_tag.to_bn();
499	
500	  buf_t e_buf = crypto::ro::hash_string(N, c_key, c, Q2, R2, m_tag, r, W1, W2, W3, W1_tag, W2_tag, W3_tag, G_tag,
501	                                        Q2_tag, C_enc_tag, sid, aux)
502	                    .bitlen(SEC_P_COM);
503	  e = bn_t::from_bin(e_buf);
504	
505	  w1_tag_tag = w1_tag + e * w1;
506	  w2_tag_tag = w2_tag + e * w2;
507	  w3_tag_tag = w3_tag + e * w3;
508	
509	  r1_w_tag_tag = r1_w_tag + e * r1_w;
510	  r2_w_tag_tag = r2_w_tag + e * r2_w;
511	  r3_w_tag_tag = r3_w_tag + e * r3_w;
512	
513	  MODULO(N) { r_enc_tag_tag = r_enc * w4.pow(e); }
514	
515	  return SUCCESS;
516	}
517	
518	error_t zk_ecdsa_sign_2pc_integer_commit_t::verify(const ecurve_t curve, const crypto::paillier_t& paillier,
519	                                                   const crypto::paillier_t::elem_t& c_key,
520	                                                   const crypto::paillier_t::elem_t& c, const ecc_point_t& Q2,
521	                                                   const ecc_point_t& R2, const bn_t& m_tag, const bn_t& r, mem_t sid,
522	                                                   uint64_t aux) const {
523	  crypto::vartime_scope_t vartime_scope;
524	  error_t rv = UNINITIALIZED_ERROR;
525	  crypto::paillier_t::rerand_scope_t paillier_rerand(crypto::paillier_t::rerand_e::off);
526	
527	  const crypto::unknown_order_pedersen_params_t& params = crypto::unknown_order_pedersen_params_t::get();
528	  const mod_t& N_ped = params.N;
529	  const bn_t& g = params.g;
530	  const bn_t& h = params.h;
531	
532	  const mod_t& N = paillier.get_N();
533	  const mod_t& NN = paillier.get_NN();
534	
535	  const mod_t& q = curve.order();
536	  const auto& G = curve.generator();
537	
538	  buf_t e_buf = crypto::ro::hash_string(N, c_key, c, Q2, R2, m_tag, r, W1, W2, W3, W1_tag, W2_tag, W3_tag, G_tag,
539	                                        Q2_tag, C_enc_tag, sid, aux)
540	                    .bitlen(SEC_P_COM);
541	  if (e != bn_t::from_bin(e_buf)) return coinbase::error(E_CRYPTO);
542	
543	  crypto::paillier_t::elem_t C_enc_tag = paillier.elem(this->C_enc_tag);
544	  crypto::paillier_t::elem_t c_key_tag = r * c_key;
545	
546	  if (rv = check_right_open_range(0, r1_w_tag_tag, N_ped << (2 * SEC_P_STAT + SEC_P_COM + 1))) return rv;
547	  if (rv = check_right_open_range(0, r2_w_tag_tag, N_ped << (2 * SEC_P_STAT + SEC_P_COM + 1))) return rv;
548	  if (rv = check_right_open_range(0, r3_w_tag_tag, N_ped << (2 * SEC_P_STAT + SEC_P_COM + 1))) return rv;
549	
550	  if (rv = curve.check(Q2)) return coinbase::error(rv, "zk_ecdsa_sign_2pc_integer_commit_t::verify: check Q2 failed");
551	  if (rv = curve.check(R2)) return coinbase::error(rv, "zk_ecdsa_sign_2pc_integer_commit_t::verify: check R2 failed");
552	  if (rv = curve.check(G_tag))
553	    return coinbase::error(rv, "zk_ecdsa_sign_2pc_integer_commit_t::verify: check G_tag failed");
554	  if (rv = curve.check(Q2_tag))
555	    return coinbase::error(rv, "zk_ecdsa_sign_2pc_integer_commit_t::verify: check Q2_tag failed");
556	
557	  if (rv = check_right_open_range(0, m_tag, q)) return rv;
558	  if (rv = check_right_open_range(0, r, q)) return rv;
559	
560	  if (rv = check_open_range(0, W1, N_ped)) return rv;
561	  if (rv = check_open_range(0, W2, N_ped)) return rv;
562	  if (rv = check_open_range(0, W3, N_ped)) return rv;
563	  if (rv = check_open_range(0, W1_tag, N_ped)) return rv;
564	  if (rv = check_open_range(0, W2_tag, N_ped)) return rv;
565	  if (rv = check_open_range(0, W3_tag, N_ped)) return rv;
566	
567	  if (rv = check_open_range(0, C_enc_tag.to_bn(), NN)) return rv;
568	  if (rv = check_open_range(0, c_key.to_bn(), NN)) return rv;
569	  if (rv = check_open_range(0, c.to_bn(), NN)) return rv;
570	
571	  if (rv = check_right_open_range(0, w1_tag_tag, q << (SEC_P_STAT + SEC_P_COM + 1))) return rv;
572	  if (rv = check_right_open_range(0, w2_tag_tag, q << (SEC_P_STAT + SEC_P_COM + 1))) return rv;
573	  if (rv = check_right_open_range(0, w3_tag_tag, (q * q) << (3 * SEC_P_STAT + SEC_P_COM + 1))) return rv;
574	
575	  if (rv = check_open_range(0, r_enc_tag_tag, N)) return rv;
576	
577	  if (w1_tag_tag * R2 != e * G + G_tag) return coinbase::error(E_CRYPTO);
578	  if (w2_tag_tag * R2 != e * Q2 + Q2_tag) return coinbase::error(E_CRYPTO);
579	
580	  MODULO(N_ped) {
581	    if (g.pow(w1_tag_tag) * h.pow(r1_w_tag_tag) != W1_tag * W1.pow(e)) return coinbase::error(E_CRYPTO);
582	    if (g.pow(w2_tag_tag) * h.pow(r2_w_tag_tag) != W2_tag * W2.pow(e)) return coinbase::error(E_CRYPTO);
583	    if (g.pow(w3_tag_tag) * h.pow(r3_w_tag_tag) != W3_tag * W3.pow(e)) return coinbase::error(E_CRYPTO);
584	  }
585	
586	  bn_t temp = (w1_tag_tag * m_tag) + (w2_tag_tag * r) + (w3_tag_tag * q);
587	  auto left = paillier.enc(temp, r_enc_tag_tag) + (w1_tag_tag * c_key_tag);
588	  auto right = C_enc_tag + (e * c);
589	
590	  if (left != right) return coinbase::error(E_CRYPTO);
591	  return SUCCESS;
592	}
