94	error_t key_share_ecdsa_hdmpc_2p_t::derive_keys(job_2p_t& job, const key_share_ecdsa_hdmpc_2p_t& key,
95	                                                const bip32_path_t& hardened_path,
96	                                                const std::vector<bip32_path_t>& non_hardened_paths, buf_t& sid,
97	                                                std::vector<ecdsa2pc::key_t>& derived_keys) {
98	  // The begining of this function is the same as its eddsa counterpart.
99	  error_t rv = UNINITIALIZED_ERROR;
100	
101	  if (sid.empty()) {
102	    if (rv = generate_sid_fixed_mp(job, sid)) return rv;
103	  }
104	
105	  ecurve_t curve = key.curve;
106	  const auto& G = curve.generator();
107	  const mod_t& q = curve.order();
108	
109	  bn_t x_share = key.root.x_share;
110	  bn_t k_share = key.root.k_share;
111	  ecc_point_t K_share = key.root.K_share();
112	  ecc_point_t other_K_share = key.root.other_K_share();
113	  ecc_point_t Q = key.root.Q;
114	
115	  // This is VRF-Compute-2P in the spec
116	  const int delta_size = curve.size() + 16;  // 256 + 128 bits
117	  ecc_point_t Z1, Z2;
118	  ecc_point_t P = crypto::ro::hash_curve(hardened_path.get()).curve(curve);
119	  ecc_point_t Z_share = k_share * P;
120	  if (job.is_p1())
121	    Z1 = Z_share;
122	  else
123	    Z2 = Z_share;
124	  zk::dh_t zk_dh1, zk_dh2;
125	
126	  if (job.is_p1()) {
127	    zk_dh1.prove(P, K_share, Z1, k_share, sid, 1);
128	  }
129	
130	  if (rv = job.p1_to_p2(Z1, zk_dh1)) return rv;
131	
132	  if (job.is_p2()) {
133	    // Verification that Z1 is valid is done in the verify function
134	    if (rv = zk_dh1.verify(P, other_K_share, Z1, sid, 1)) return rv;
135	    zk_dh2.prove(P, K_share, Z2, k_share, sid, 2);
136	  }
137	
138	  if (rv = job.p2_to_p1(Z2, zk_dh2)) return rv;
139	
140	  if (job.is_p1()) {
141	    if (rv = zk_dh2.verify(P, other_K_share, Z2, sid, 2)) return rv;
142	  }
143	  ecc_point_t Z = Z1 + Z2;
144	  // The rest of Hard-Derive-2P
145	  // The rest of Hard-Derive-2P
146	  buf_t y = crypto::ro::hash_string(Z).bitlen(bytes_to_bits(delta_size) + 256);
147	  bn_t delta = bn_t::from_bin(y.take(delta_size)) % q;
148	  buf_t chain_code = y.skip(delta_size);
149	
150	  int n_hd_paths = (int)non_hardened_paths.size();
151	  derived_keys.resize(n_hd_paths);
152	
153	  ecc_point_t delta_G = delta * G;
154	  ecc_point_t Q_derived = Q + delta_G;
155	  std::vector<bn_t> non_hard_delta = non_hard_derive(Q_derived, chain_code, non_hardened_paths);
156	  std::vector<bn_t> derived_xs(n_hd_paths);
157	  std::vector<ecc_point_t> derived_Qs(n_hd_paths);
158	
159	  // Start of the difference with the eddsa-2pc version.
160	  for (int i = 0; i < n_hd_paths; i++) {
161	    derived_keys[i].curve = curve;
162	    derived_keys[i].paillier = coinbase::crypto::paillier_t(key.paillier);
163	    derived_keys[i].role = party_t(key.party_index);
164	    derived_keys[i].c_key = bn_t(key.c_key);
165	
166	    ecc_point_t non_hard_delta_G = non_hard_delta[i] * G;
167	    derived_keys[i].Q = Q_derived + non_hard_delta_G;
168	    if (job.get_party() == party_t::p2)
169	      MODULO(q) derived_keys[i].x_share = x_share + delta + non_hard_delta[i];
170	    else
171	      derived_keys[i].x_share = x_share;
172	  }
173	
174	  return SUCCESS;
175	}
