34	error_t blob_to_key(const key_blob_v1_t& blob, coinbase::mpc::ecdsa2pc::key_t& key) {
35	  if (blob.role > 1) return coinbase::error(E_FORMAT, "invalid key blob role");
36	
37	  const auto cid = static_cast<curve_id>(blob.curve);
38	  if (cid == curve_id::ed25519) return coinbase::error(E_FORMAT, "invalid key blob curve");
39	  auto curve = to_internal_curve(cid);
40	  if (!curve.valid()) return coinbase::error(E_FORMAT, "invalid key blob curve");
41	
42	  key.role = static_cast<coinbase::mpc::party_t>(static_cast<int32_t>(blob.role));
43	  key.curve = curve;
44	
45	  // Defensive validation at the opaque blob boundary.
46	  //
47	  // In our ECDSA-2PC protocol, party P1 owns the Paillier private key, and `c_key` is an encryption of P1's share under
48	  // that key. Reject malformed / tampered blobs early.
49	  const bool paillier_has_private = blob.paillier.has_private_key();
50	  if ((blob.role == 0) != paillier_has_private) return coinbase::error(E_FORMAT, "invalid key blob");
51	
52	  const auto& N = blob.paillier.get_N();
53	  if (N.value().get_bits_count() < coinbase::crypto::paillier_t::bit_size) {
54	    return coinbase::error(E_FORMAT, "invalid key blob");
55	  }
56	
57	  // Intentionally do not enforce `x_share in [0, q)` here:
58	  // in ECDSA-2PC this share is maintained as a Paillier-compatible integer representative and can be
59	  // unreduced after refresh, so rejecting non-reduced values would break valid refreshed key blobs.
60	  //
61	  // However, `x_share` must remain in Z_N so that Paillier-related operations are well-defined and to avoid
62	  // attacker-controlled bignum blowups.
63	  if (!N.is_in_range(blob.x_share)) return coinbase::error(E_FORMAT, "invalid key blob");
64	
65	  // Ensure `c_key` is a well-formed Paillier ciphertext under this key.
66	  {
67	    coinbase::crypto::vartime_scope_t vartime_scope;
68	    if (blob.paillier.verify_cipher(blob.c_key)) return coinbase::error(E_FORMAT, "invalid key blob");
69	  }
70	
71	  // If we have the private key (P1), bind the share to its Paillier encryption.
72	  if (paillier_has_private) {
73	    const coinbase::crypto::bn_t plain = blob.paillier.decrypt(blob.c_key);
74	    if (plain != N.mod(blob.x_share)) return coinbase::error(E_FORMAT, "invalid key blob");
75	  }
76	
77	  key.x_share = blob.x_share;
78	  key.c_key = blob.c_key;
79	  key.paillier = blob.paillier;
80	
81	  if (const error_t rv = key.Q.from_bin(curve, blob.Q_compressed)) return rv;
82	  if (curve.check(key.Q)) return coinbase::error(E_FORMAT, "invalid key blob");
83	  return SUCCESS;
84	}
