86	error_t serialize_key_blob(const coinbase::mpc::ecdsa2pc::key_t& key, buf_t& out) {
87	  curve_id cid;
88	  if (!from_internal_curve(key.curve, cid)) return coinbase::error(E_BADARG, "unsupported curve");
89	  if (cid == curve_id::ed25519) return coinbase::error(E_BADARG, "unsupported curve");
90	
91	  key_blob_v1_t blob;
92	  blob.role = static_cast<uint32_t>(key.role);
93	  blob.curve = static_cast<uint32_t>(cid);
94	  blob.Q_compressed = key.Q.to_compressed_bin();
95	  blob.x_share = key.x_share;
96	  blob.c_key = key.c_key;
97	  blob.paillier = key.paillier;
98	  out = coinbase::convert(blob);
99	  return SUCCESS;
100	}
101	
102	error_t deserialize_key_blob(mem_t in, coinbase::mpc::ecdsa2pc::key_t& key) {
103	  // Reject unsupported versions before attempting to parse variable-length fields.
104	  // This prevents mis-parsing newer blob versions with incompatible encodings.
105	  if (in.size < 4) return coinbase::error(E_FORMAT, "invalid key blob");
106	  const uint32_t version = coinbase::be_get_4(in.data);
107	  if (version != key_blob_version_v1) return coinbase::error(E_FORMAT, "unsupported key blob version");
108	
109	  key_blob_v1_t blob;
110	  const error_t rv = coinbase::convert(blob, in);
111	  if (rv) return rv;
112	  if (blob.version != key_blob_version_v1) return coinbase::error(E_FORMAT, "unsupported key blob version");
113	  return blob_to_key(blob, key);
114	}
