118	error_t dkg(const coinbase::api::job_2p_t& job, curve_id curve, buf_t& key_blob) {
119	  if (const error_t rv = validate_job_2p(job)) return rv;
120	  if (curve == curve_id::ed25519) return coinbase::error(E_BADARG, "unsupported curve");
121	  auto icurve = to_internal_curve(curve);
122	  if (!icurve.valid()) return coinbase::error(E_BADARG, "unsupported curve");
123	
124	  coinbase::mpc::job_2p_t mpc_job = to_internal_job(job);
125	
126	  coinbase::mpc::ecdsa2pc::key_t key;
127	  const error_t rv = coinbase::mpc::ecdsa2pc::dkg(mpc_job, icurve, key);
128	  if (rv) return rv;
129	
130	  return serialize_key_blob(key, key_blob);
131	}
