133	error_t refresh(const coinbase::api::job_2p_t& job, mem_t key_blob, buf_t& new_key_blob) {
134	  if (const error_t rv = validate_job_2p(job)) return rv;
135	  if (const error_t rv = coinbase::api::detail::validate_mem_arg_max_size(key_blob, "key_blob",
136	                                                                          coinbase::api::detail::MAX_OPAQUE_BLOB_SIZE))
137	    return rv;
138	  coinbase::mpc::ecdsa2pc::key_t key;
139	  error_t rv = deserialize_key_blob(key_blob, key);
140	  if (rv) return rv;
141	
142	  const auto self = to_internal_party(job.self);
143	  if (key.role != self) return coinbase::error(E_BADARG, "job.self mismatch key blob role");
144	
145	  coinbase::mpc::job_2p_t mpc_job = to_internal_job(job);
146	
147	  coinbase::mpc::ecdsa2pc::key_t new_key;
148	  rv = coinbase::mpc::ecdsa2pc::refresh(mpc_job, key, new_key);
149	  if (rv) return rv;
150	
151	  return serialize_key_blob(new_key, new_key_blob);
152	}
